mapper.select:
SELECT * FROM ( SELECT M.MEMBER_NO AS memberNo, M.MEMBER_NAME AS memberName, M.EMAIL AS email, M.PHONE AS phone, M.GRADE_CD AS gradeCd, M.POINT_BALANCE AS pointBalance, M.STATUS_CD AS statusCd, M.JOIN_DATE AS joinDate, M.LAST_LOGIN_DATE AS lastLoginDate, M.SUSPEND_END_DATE AS suspendEndDate, CASE WHEN EXISTS ( SELECT 1 FROM TB_BUSINESS B WHERE B.BIZ_ID = M.MEMBER_ID AND B.STATUS_CD = 'APPROVED' ) THEN 'BIZ' ELSE 'GENERAL' END AS roleType, ROW_NUMBER() OVER (ORDER BY M.JOIN_DATE DESC) AS rn FROM TB_MEMBER M WHERE 1 = 1
AND (M.MEMBER_NAME LIKE '%' || #{keyword} || '%' OR M.EMAIL LIKE '%' || #{keyword} || '%' OR M.PHONE LIKE '%' || #{keyword} || '%')
AND M.STATUS_CD = #{statusCd}
AND EXISTS ( SELECT 1 FROM TB_BUSINESS B WHERE B.BIZ_ID = M.MEMBER_ID AND B.STATUS_CD = 'APPROVED' )
AND NOT EXISTS ( SELECT 1 FROM TB_BUSINESS B WHERE B.BIZ_ID = M.MEMBER_ID AND B.STATUS_CD = 'APPROVED' )
) WHERE rn BETWEEN #{offset} + 1 AND #{offset} + #{limit}

mapper.update:
UPDATE TB_MEMBER
SET GRADE_CD = #{gradeCd}
WHERE MEMBER_NO = #{memberNo}

UPDATE TB_MEMBER
SET POINT_BALANCE = NVL(POINT_BALANCE, 0) + #{amount}
WHERE MEMBER_NO = #{memberNo}

UPDATE TB_MEMBER
SET POINT_BALANCE = NVL(POINT_BALANCE, 0) - #{amount}
WHERE MEMBER_NO = #{memberNo}
  AND NVL(POINT_BALANCE, 0) >= #{amount}

UPDATE TB_MEMBER
SET STATUS_CD = #{statusCd}
WHERE MEMBER_NO IN

  #{no}

UPDATE TB_MEMBER
SET STATUS_CD = 'SUSPENDED',
    SUSPEND_END_DATE = #{suspendEndDate, jdbcType=TIMESTAMP}
WHERE MEMBER_NO = #{memberNo}

UPDATE TB_MEMBER
SET STATUS_CD = 'SUSPENDED',
    SUSPEND_END_DATE = #{suspendEndDate, jdbcType=TIMESTAMP}
WHERE MEMBER_NO IN

  #{no}
